const xParabola = [];
const yParabola = [];
for (let i = -2.5; i <= 2.5; i += 0.05) {
  xParabola.push(i);
  yParabola.push(i * i);
}

const px = 1.5;
const py = px * px;

const parabolaTrace = {
  x: xParabola,
  y: yParabola,
  type: 'scatter',
  mode: 'lines',
  name: 'f(x) = x²',
  line: { color: '#3b82f6', width: 3 }
};

const triangleTrace = {
  x: [0, px, px, 0],
  y: [0, 0, py, 0],
  fill: 'toself',
  fillcolor: 'rgba(16, 185, 129, 0.2)',
  line: { color: '#10b981', width: 2, dash: 'dash' },
  name: 'Right Triangle',
  type: 'scatter',
  mode: 'lines+markers',
  marker: { size: 4 }
};

const pointTrace = {
  x: [px],
  y: [py],
  mode: 'markers+text',
  text: [`P(${px}, ${py})`],
  textposition: 'top center',
  marker: {
    color: '#ef4444',
    size: 12,
    line: { color: '#ffffff', width: 2 }
  },
  name: 'Point on Curve'
};

const angleIndicator = {
  x: [px - 0.2, px - 0.2, px],
  y: [0, 0.2, 0.2],
  mode: 'lines',
  line: { color: '#94a3b8', width: 1 },
  showlegend: false,
  name: 'Right Angle'
};

return [parabolaTrace, triangleTrace, pointTrace, angleIndicator];
